select v_1 as "l_orderkey", v_2 as "revenue", v_3 as "o_orderdate", v_4 as "o_shippriority" from (select v_5 as v_1, v_6 as v_3, v_7 as v_4, sum(v_8 * (cast('1' as integer) - v_9)) as v_2 from (select * from (select * from (select * from (select "c_custkey" as v_10, "c_name" as v_11, "c_address" as v_12, "c_nationkey" as v_13, "c_phone" as v_14, "c_acctbal" as v_15, "c_mktsegment" as v_16, "c_comment" as v_17 from "customer") s where v_16 = 'BUILDING') l inner join (select * from (select "o_orderkey" as v_18, "o_custkey" as v_19, "o_orderstatus" as v_20, "o_totalprice" as v_21, "o_orderdate" as v_6, "o_orderpriority" as v_22, "o_clerk" as v_23, "o_shippriority" as v_7, "o_comment" as v_24 from "orders") s where v_6 < (date('1995-03-15'))) r on v_10 = v_19) l inner join (select * from (select "l_orderkey" as v_5, "l_partkey" as v_25, "l_suppkey" as v_26, "l_linenumber" as v_27, "l_quantity" as v_28, "l_extendedprice" as v_8, "l_discount" as v_9, "l_tax" as v_29, "l_returnflag" as v_30, "l_linestatus" as v_31, "l_shipdate" as v_32, "l_commitdate" as v_33, "l_receiptdate" as v_34, "l_shipinstruct" as v_35, "l_shipmode" as v_36, "l_comment" as v_37 from "lineitem") s where v_32 > (date('1995-03-15'))) r on v_5 = v_18) s group by 1, 2, 3) s order by v_2 desc, v_3 limit 10
